SET NOCOUNT ON;
GO

IF OBJECT_ID('dbo.LeHoi', 'U') IS NULL
BEGIN
    CREATE TABLE dbo.LeHoi (
        LeHoiID                   INT IDENTITY(1,1) PRIMARY KEY,
        MaLeHoi                   VARCHAR(50) NOT NULL UNIQUE,
        LoaiBanGhi                VARCHAR(20) NOT NULL DEFAULT 'FESTIVAL',
        ThuTuHienThi              INT NOT NULL DEFAULT 0,
        TieuDeVI                  NVARCHAR(300) NULL,
        TieuDeEN                  NVARCHAR(300) NULL,
        TieuDePhuVI               NVARCHAR(300) NULL,
        TieuDePhuEN               NVARCHAR(300) NULL,
        ShortTitleVI              NVARCHAR(200) NULL,
        ShortTitleEN              NVARCHAR(200) NULL,
        MoTaNganVI                NVARCHAR(1500) NULL,
        MoTaNganEN                NVARCHAR(1500) NULL,
        HeroDescVI                NVARCHAR(1500) NULL,
        HeroDescEN                NVARCHAR(1500) NULL,
        ViTriVI                   NVARCHAR(300) NULL,
        ViTriEN                   NVARCHAR(300) NULL,
        NgayLeVI                  NVARCHAR(200) NULL,
        NgayLeEN                  NVARCHAR(200) NULL,
        TagVI                     NVARCHAR(150) NULL,
        TagEN                     NVARCHAR(150) NULL,
        TagColor                  VARCHAR(20) NULL,
        TimelineMonthVI           NVARCHAR(100) NULL,
        TimelineMonthEN           NVARCHAR(100) NULL,
        TimelineSeasonVI          NVARCHAR(100) NULL,
        TimelineSeasonEN          NVARCHAR(100) NULL,
        TimelineColor             VARCHAR(20) NULL,
        ImageUrl                  NVARCHAR(1000) NULL,
        ImageAltVI                NVARCHAR(500) NULL,
        ImageAltEN                NVARCHAR(500) NULL,
        TimelineImageUrl          NVARCHAR(1000) NULL,
        TimelineImageAltVI        NVARCHAR(500) NULL,
        TimelineImageAltEN        NVARCHAR(500) NULL,
        PageBadgeVI               NVARCHAR(200) NULL,
        PageBadgeEN               NVARCHAR(200) NULL,
        PageTitleLine1VI          NVARCHAR(200) NULL,
        PageTitleLine1EN          NVARCHAR(200) NULL,
        PageTitleAccentVI         NVARCHAR(200) NULL,
        PageTitleAccentEN         NVARCHAR(200) NULL,
        PageTitleLine3VI          NVARCHAR(200) NULL,
        PageTitleLine3EN          NVARCHAR(200) NULL,
        PageSubtitleVI            NVARCHAR(1500) NULL,
        PageSubtitleEN            NVARCHAR(1500) NULL,
        PageStatsJsonVI           NVARCHAR(MAX) NULL,
        PageStatsJsonEN           NVARCHAR(MAX) NULL,
        TimelineItemsJsonVI       NVARCHAR(MAX) NULL,
        TimelineItemsJsonEN       NVARCHAR(MAX) NULL,
        GalleryImagesJsonVI       NVARCHAR(MAX) NULL,
        GalleryImagesJsonEN       NVARCHAR(MAX) NULL,
        PageHeroImageUrl          NVARCHAR(1000) NULL,
        PageHeroImageAltVI        NVARCHAR(500) NULL,
        PageHeroImageAltEN        NVARCHAR(500) NULL,
        SearchPlaceholderVI       NVARCHAR(300) NULL,
        SearchPlaceholderEN       NVARCHAR(300) NULL,
        FilterButtonVI            NVARCHAR(200) NULL,
        FilterButtonEN            NVARCHAR(200) NULL,
        AllRegionsVI              NVARCHAR(100) NULL,
        AllRegionsEN              NVARCHAR(100) NULL,
        AllMonthsVI               NVARCHAR(100) NULL,
        AllMonthsEN               NVARCHAR(100) NULL,
        AllCategoriesVI           NVARCHAR(100) NULL,
        AllCategoriesEN           NVARCHAR(100) NULL,
        AllEthnicGroupsVI         NVARCHAR(150) NULL,
        AllEthnicGroupsEN         NVARCHAR(150) NULL,
        MajorBadgeVI              NVARCHAR(200) NULL,
        MajorBadgeEN              NVARCHAR(200) NULL,
        MajorTitleVI              NVARCHAR(300) NULL,
        MajorTitleEN              NVARCHAR(300) NULL,
        MajorSubtitleVI           NVARCHAR(1500) NULL,
        MajorSubtitleEN           NVARCHAR(1500) NULL,
        AllTitleVI                NVARCHAR(300) NULL,
        AllTitleEN                NVARCHAR(300) NULL,
        AllSubtitleVI             NVARCHAR(1500) NULL,
        AllSubtitleEN             NVARCHAR(1500) NULL,
        TimelineBadgeVI           NVARCHAR(200) NULL,
        TimelineBadgeEN           NVARCHAR(200) NULL,
        TimelineTitleVI           NVARCHAR(300) NULL,
        TimelineTitleEN           NVARCHAR(300) NULL,
        TimelineSubtitleVI        NVARCHAR(1500) NULL,
        TimelineSubtitleEN        NVARCHAR(1500) NULL,
        TimelineHintVI            NVARCHAR(200) NULL,
        TimelineHintEN            NVARCHAR(200) NULL,
        GalleryBadgeVI            NVARCHAR(200) NULL,
        GalleryBadgeEN            NVARCHAR(200) NULL,
        GalleryTitleVI            NVARCHAR(300) NULL,
        GalleryTitleEN            NVARCHAR(300) NULL,
        GallerySubtitleVI         NVARCHAR(1500) NULL,
        GallerySubtitleEN         NVARCHAR(1500) NULL,
        MeaningBadgeVI            NVARCHAR(200) NULL,
        MeaningBadgeEN            NVARCHAR(200) NULL,
        MeaningTitleVI            NVARCHAR(300) NULL,
        MeaningTitleEN            NVARCHAR(300) NULL,
        MeaningParagraphsJsonVI   NVARCHAR(MAX) NULL,
        MeaningParagraphsJsonEN   NVARCHAR(MAX) NULL,
        MeaningButtonVI           NVARCHAR(200) NULL,
        MeaningButtonEN           NVARCHAR(200) NULL,
        MeaningButtonHref         NVARCHAR(300) NULL,
        QuoteTitleVI              NVARCHAR(300) NULL,
        QuoteTitleEN              NVARCHAR(300) NULL,
        QuoteSubtitleVI           NVARCHAR(300) NULL,
        QuoteSubtitleEN           NVARCHAR(300) NULL,
        QuoteDescVI               NVARCHAR(1500) NULL,
        QuoteDescEN               NVARCHAR(1500) NULL,
        QuoteButtonVI             NVARCHAR(200) NULL,
        QuoteButtonEN             NVARCHAR(200) NULL,
        QuoteBackgroundImageUrl   NVARCHAR(1000) NULL,
        QuoteBackgroundImageAltVI NVARCHAR(500) NULL,
        QuoteBackgroundImageAltEN NVARCHAR(500) NULL,
        NoiDungJsonVI             NVARCHAR(MAX) NULL,
        NoiDungJsonEN             NVARCHAR(MAX) NULL,
        HoatDong                  BIT NOT NULL DEFAULT 1,
        NgayTao                   DATETIME2 NOT NULL DEFAULT SYSUTCDATETIME(),
        NgayCapNhat               DATETIME2 NOT NULL DEFAULT SYSUTCDATETIME()
    );
END
GO

MERGE dbo.LeHoi AS target
USING (SELECT 'LE_HOI_PAGE' AS MaLeHoi) AS src
ON target.MaLeHoi = src.MaLeHoi
WHEN MATCHED THEN
  UPDATE SET
    LoaiBanGhi = 'PAGE',
    ThuTuHienThi = 0,
    PageBadgeVI = N'Lễ hội · Văn hóa · Truyền thống',
    PageTitleLine1VI = N'Tinh hoa',
    PageTitleAccentVI = N'Lễ hội',
    PageTitleLine3VI = N'Việt Nam',
    PageSubtitleVI = N'Hàng nghìn năm truyền thống hội tụ trong từng lễ hội — nơi sắc màu, âm thanh và tâm hồn Việt hòa quyện thành một.',
    PageStatsJsonVI = N'[{"value":"8.000+","label":"Lễ hội hàng năm"},{"value":"54","label":"Dân tộc anh em"},{"value":"63","label":"Tỉnh thành"}]',
    TimelineItemsJsonVI = N'[{"id":1,"month":"Tháng 1","title":"Tết Nguyên Đán","season":"Mùa xuân","color":"#e11d48","image":"/images/banner1.jpg"},{"id":2,"month":"Tháng 4","title":"Giỗ Tổ Hùng Vương","season":"Mùa xuân","color":"#ea580c","image":"/images/giotohungvuong1.PNG"},{"id":3,"month":"Tháng 6","title":"Festival Huế","season":"Mùa hạ","color":"#10b981","image":"/images/festival_hue.png"},{"id":4,"month":"Tháng 9","title":"Tết Trung Thu","season":"Mùa thu","color":"#d946ef","image":"/images/banner2.jpg"},{"id":5,"month":"Tháng 10","title":"Lễ hội Katê","season":"Mùa thu","color":"#f59e0b","image":"/images/cham.jpg"},{"id":6,"month":"Tháng 12","title":"Nghinh Ông","season":"Mùa đông","color":"#6366f1","image":"/images/banner3.jpg"}]',
    GalleryImagesJsonVI = N'[{"imageUrl":"/images/banner2.jpg","alt":"Khoảnh khắc lễ hội"},{"imageUrl":"/images/banner1.jpg","alt":"Không gian lễ hội mùa xuân"},{"imageUrl":"/images/festival_banner.jpg","alt":"Cảnh lễ hội Việt Nam"},{"imageUrl":"/images/banner3.jpg","alt":"Nghi thức lễ hội"},{"imageUrl":"/images/festival_hue.png","alt":"Festival Huế"},{"imageUrl":"/images/giotohungvuong1.PNG","alt":"Giỗ Tổ Hùng Vương"},{"imageUrl":"/images/hmong_festival_gau_tao_1775575986843.png","alt":"Lễ hội Gầu Tào"},{"imageUrl":"/images/hat-quan-ho.png","alt":"Quan họ"},{"imageUrl":"/images/cham.jpg","alt":"Không gian lễ hội Katê"}]',
    PageHeroImageUrl = N'/images/festival_banner.jpg',
    PageHeroImageAltVI = N'Ảnh bìa trang lễ hội',
    SearchPlaceholderVI = N'Tìm kiếm lễ hội, nghi lễ và truyền thống...',
    FilterButtonVI = N'Bộ lọc nâng cao',
    AllRegionsVI = N'Tất cả khu vực',
    AllMonthsVI = N'Tất cả tháng',
    AllCategoriesVI = N'Tất cả loại hình',
    AllEthnicGroupsVI = N'Tất cả nhóm trải nghiệm',
    MajorBadgeVI = N'Lễ hội nổi bật',
    MajorTitleVI = N'Lễ hội tiêu biểu',
    MajorSubtitleVI = N'Khám phá những lễ hội nổi bật và có sức lan tỏa mạnh mẽ trong văn hóa Việt Nam.',
    AllTitleVI = N'Khám phá các lễ hội Việt Nam',
    AllSubtitleVI = N'Mở từng trang để xem nội dung lễ hội tương ứng được tải động từ hệ thống.',
    TimelineBadgeVI = N'Lễ hội quanh năm',
    TimelineTitleVI = N'Dòng thời gian lễ hội',
    TimelineSubtitleVI = N'Khám phá nhịp điệu văn hóa Việt Nam qua từng mùa trong năm.',
    TimelineHintVI = N'Cuộn ngang để xem thêm →',
    GalleryBadgeVI = N'Hành trình thị giác',
    GalleryTitleVI = N'Khoảnh khắc lễ hội',
    GallerySubtitleVI = N'Đắm mình trong bầu không khí và cảm xúc của những mùa lễ hội Việt Nam.',
    MeaningBadgeVI = N'Ý nghĩa văn hóa',
    MeaningTitleVI = N'Linh hồn của lễ hội Việt',
    MeaningParagraphsJsonVI = N'["Lễ hội Việt Nam không chỉ là những ngày vui mà còn là nơi kết nối con người với cội nguồn, vùng đất và ký ức cộng đồng.","Mỗi nghi thức, biểu tượng và hoạt động trong lễ hội đều phản ánh chiều sâu văn hóa, niềm tin và tinh thần gắn kết của người Việt.","Khi tham gia lễ hội, chúng ta không chỉ quan sát mà còn trực tiếp cảm nhận nhịp sống văn hóa đang tiếp tục được lưu truyền qua nhiều thế hệ."]',
    MeaningButtonVI = N'Tìm hiểu thêm về văn hóa Việt',
    MeaningButtonHref = N'/articles',
    QuoteTitleVI = N'Uống nước nhớ nguồn',
    QuoteSubtitleVI = N'Nhớ về cội nguồn để gìn giữ giá trị văn hóa',
    QuoteDescVI = N'Tinh thần biết ơn cội nguồn chính là nền tảng để các lễ hội Việt Nam tiếp tục sống động trong đời sống hôm nay.',
    QuoteButtonVI = N'Khám phá văn hóa',
    QuoteBackgroundImageUrl = N'/images/banner1.jpg',
    QuoteBackgroundImageAltVI = N'Ảnh nền trích dẫn trang lễ hội',
    HoatDong = 1,
    NgayCapNhat = SYSUTCDATETIME()
WHEN NOT MATCHED THEN
  INSERT (
    MaLeHoi,LoaiBanGhi,ThuTuHienThi,PageBadgeVI,PageTitleLine1VI,PageTitleAccentVI,PageTitleLine3VI,PageSubtitleVI,
    PageStatsJsonVI,TimelineItemsJsonVI,GalleryImagesJsonVI,PageHeroImageUrl,PageHeroImageAltVI,SearchPlaceholderVI,
    FilterButtonVI,AllRegionsVI,AllMonthsVI,AllCategoriesVI,AllEthnicGroupsVI,MajorBadgeVI,MajorTitleVI,MajorSubtitleVI,
    AllTitleVI,AllSubtitleVI,TimelineBadgeVI,TimelineTitleVI,TimelineSubtitleVI,TimelineHintVI,GalleryBadgeVI,
    GalleryTitleVI,GallerySubtitleVI,MeaningBadgeVI,MeaningTitleVI,MeaningParagraphsJsonVI,MeaningButtonVI,MeaningButtonHref,
    QuoteTitleVI,QuoteSubtitleVI,QuoteDescVI,QuoteButtonVI,QuoteBackgroundImageUrl,QuoteBackgroundImageAltVI,HoatDong
  )
  VALUES (
    'LE_HOI_PAGE','PAGE',0,N'Lễ hội · Văn hóa · Truyền thống',N'Tinh hoa',N'Lễ hội',N'Việt Nam',N'Hàng nghìn năm truyền thống hội tụ trong từng lễ hội — nơi sắc màu, âm thanh và tâm hồn Việt hòa quyện thành một.',
    N'[{"value":"8.000+","label":"Lễ hội hàng năm"},{"value":"54","label":"Dân tộc anh em"},{"value":"63","label":"Tỉnh thành"}]',
    N'[{"id":1,"month":"Tháng 1","title":"Tết Nguyên Đán","season":"Mùa xuân","color":"#e11d48","image":"/images/banner1.jpg"},{"id":2,"month":"Tháng 4","title":"Giỗ Tổ Hùng Vương","season":"Mùa xuân","color":"#ea580c","image":"/images/giotohungvuong1.PNG"},{"id":3,"month":"Tháng 6","title":"Festival Huế","season":"Mùa hạ","color":"#10b981","image":"/images/festival_hue.png"},{"id":4,"month":"Tháng 9","title":"Tết Trung Thu","season":"Mùa thu","color":"#d946ef","image":"/images/banner2.jpg"},{"id":5,"month":"Tháng 10","title":"Lễ hội Katê","season":"Mùa thu","color":"#f59e0b","image":"/images/cham.jpg"},{"id":6,"month":"Tháng 12","title":"Nghinh Ông","season":"Mùa đông","color":"#6366f1","image":"/images/banner3.jpg"}]',
    N'[{"imageUrl":"/images/banner2.jpg","alt":"Khoảnh khắc lễ hội"},{"imageUrl":"/images/banner1.jpg","alt":"Không gian lễ hội mùa xuân"},{"imageUrl":"/images/festival_banner.jpg","alt":"Cảnh lễ hội Việt Nam"},{"imageUrl":"/images/banner3.jpg","alt":"Nghi thức lễ hội"},{"imageUrl":"/images/festival_hue.png","alt":"Festival Huế"},{"imageUrl":"/images/giotohungvuong1.PNG","alt":"Giỗ Tổ Hùng Vương"},{"imageUrl":"/images/hmong_festival_gau_tao_1775575986843.png","alt":"Lễ hội Gầu Tào"},{"imageUrl":"/images/hat-quan-ho.png","alt":"Quan họ"},{"imageUrl":"/images/cham.jpg","alt":"Không gian lễ hội Katê"}]',
    N'/images/festival_banner.jpg',N'Ảnh bìa trang lễ hội',N'Tìm kiếm lễ hội, nghi lễ và truyền thống...',N'Bộ lọc nâng cao',N'Tất cả khu vực',N'Tất cả tháng',N'Tất cả loại hình',N'Tất cả nhóm trải nghiệm',N'Lễ hội nổi bật',N'Lễ hội tiêu biểu',N'Khám phá những lễ hội nổi bật và có sức lan tỏa mạnh mẽ trong văn hóa Việt Nam.',N'Khám phá các lễ hội Việt Nam',N'Mở từng trang để xem nội dung lễ hội tương ứng được tải động từ hệ thống.',N'Lễ hội quanh năm',N'Dòng thời gian lễ hội',N'Khám phá nhịp điệu văn hóa Việt Nam qua từng mùa trong năm.',N'Cuộn ngang để xem thêm →',N'Hành trình thị giác',N'Khoảnh khắc lễ hội',N'Đắm mình trong bầu không khí và cảm xúc của những mùa lễ hội Việt Nam.',N'Ý nghĩa văn hóa',N'Linh hồn của lễ hội Việt',N'["Lễ hội Việt Nam không chỉ là những ngày vui mà còn là nơi kết nối con người với cội nguồn, vùng đất và ký ức cộng đồng.","Mỗi nghi thức, biểu tượng và hoạt động trong lễ hội đều phản ánh chiều sâu văn hóa, niềm tin và tinh thần gắn kết của người Việt.","Khi tham gia lễ hội, chúng ta không chỉ quan sát mà còn trực tiếp cảm nhận nhịp sống văn hóa đang tiếp tục được lưu truyền qua nhiều thế hệ."]',N'Tìm hiểu thêm về văn hóa Việt',N'/articles',N'Uống nước nhớ nguồn',N'Nhớ về cội nguồn để gìn giữ giá trị văn hóa',N'Tinh thần biết ơn cội nguồn chính là nền tảng để các lễ hội Việt Nam tiếp tục sống động trong đời sống hôm nay.',N'Khám phá văn hóa',N'/images/banner1.jpg',N'Ảnh nền trích dẫn trang lễ hội',1
  );
