UPDATE dbo.LeHoi
SET
  LoaiBanGhi = 'FESTIVAL', ThuTuHienThi = 1, TieuDeVI = N'Tết Nguyên Đán', TieuDePhuVI = N'Tết cổ truyền Việt Nam', ShortTitleVI = N'Tết',
  MoTaNganVI = N'Lễ tết quan trọng nhất trong năm của người Việt, gắn với đoàn viên gia đình và khởi đầu năm mới.',
  HeroDescVI = N'Lễ hội lớn nhất trong năm, tôn vinh đoàn viên, tổ tiên và khởi đầu mới.', ViTriVI = N'Toàn quốc', NgayLeVI = N'Tháng 1 - Tháng 2',
  TagVI = N'Lễ hội lớn', TagColor = '#ce112d', ImageUrl = N'/images/banner1.jpg', ImageAltVI = N'Tết Nguyên Đán', TimelineMonthVI = N'Tháng 1',
  TimelineSeasonVI = N'Mùa xuân', TimelineImageUrl = N'/images/banner1.jpg', TimelineImageAltVI = N'Tết Nguyên Đán', TimelineColor = '#e11d48',
  NoiDungJsonVI = N'{"whatIsItContext":["Tết Nguyên Đán là dịp chuyển giao giữa năm cũ và năm mới theo âm lịch, gắn với tinh thần đoàn viên, tưởng nhớ tổ tiên và khởi đầu một chu kỳ sống mới.","Trong những ngày Tết, các gia đình dọn dẹp nhà cửa, chuẩn bị mâm cỗ, trang hoàng không gian sống và dành thời gian sum họp bên nhau."],"quickFacts":{"date":"Cuối tháng Chạp đến đầu tháng Giêng âm lịch","location":"Toàn quốc","participants":"Mọi gia đình và cộng đồng"},"howItIsCelebrated":[{"phase":"Chuẩn bị","title":"Dọn dẹp và sắm Tết","desc":["Người Việt sửa soạn nhà cửa, mua hoa, gói bánh và chuẩn bị lễ vật cúng ông bà.","Không khí Tết bắt đầu từ những ngày cuối năm khi chợ hoa, phố phường và từng gia đình đều rộn ràng chuẩn bị."],"image":"/images/anhtet1.PNG","align":"left"},{"phase":"Giao thừa","title":"Khoảnh khắc chuyển năm","desc":["Đêm giao thừa là thời khắc linh thiêng để cúng tổ tiên, cầu bình an và chào đón năm mới.","Nhiều gia đình quây quần bên nhau, nghe lời chúc đầu năm và tận hưởng cảm giác mở đầu mới mẻ."],"image":"/images/banner2.jpg","align":"right"},{"phase":"Đầu xuân","title":"Chúc Tết và du xuân","desc":["Mọi người thăm hỏi họ hàng, lì xì trẻ em, đi lễ chùa và tham gia các hoạt động hội xuân.","Những nghi thức đầu năm thể hiện sự gắn kết gia đình, niềm tin vào may mắn và ước vọng tốt đẹp."],"image":"/images/banner3.jpg","align":"left"}],"whatTetFeelsLike":{"leftText":["Đường phố: Ngập tràn sắc đỏ, đào, mai và không khí nô nức đón xuân.","Âm thanh: Tiếng chúc Tết, tiếng cười nói, tiếng nhạc xuân và nhịp điệu hội hè vang lên khắp nơi.","Nhịp sống: Từ tất bật chuẩn bị chuyển sang khoảnh khắc sum họp, ấm áp và đầy hy vọng."],"rightText":["Mái nhà: Được trang hoàng sạch đẹp với mâm ngũ quả, câu đối và bàn thờ tổ tiên tươm tất.","Cảm xúc: Là sự hòa quyện giữa hoài niệm, biết ơn và mong ước cho một năm bình an hơn.","Trải nghiệm: Dù ở thành thị hay nông thôn, Tết luôn tạo cảm giác thuộc về và gắn kết rất sâu sắc."],"image":"/images/festival_banner.jpg"},"keyTraditionsDocs":[{"image":"/images/banner2.jpg","title":"Lì xì đầu năm","desc":"Phong tục mừng tuổi mang lời chúc may mắn, sức khỏe và thành công."},{"image":"/images/banner3.jpg","title":"Bánh chưng - bánh tét","desc":"Món ăn biểu tượng của Tết, thể hiện sự biết ơn với đất trời và tổ tiên."},{"image":"/images/anhtet1.PNG","title":"Cúng gia tiên","desc":"Nghi thức quan trọng giúp kết nối các thế hệ trong gia đình."}],"traditionalFoods":[{"image":"/images/banner3.jpg","title":"Bánh chưng","desc":"Món bánh truyền thống gắn với Tết miền Bắc."},{"image":"/images/banner2.jpg","title":"Thịt kho trứng","desc":"Món ăn quen thuộc trong mâm cơm Tết nhiều gia đình."},{"image":"/images/festival_banner.jpg","title":"Mứt Tết","desc":"Hương vị ngọt ngào thường dùng để tiếp khách đầu xuân."}],"regionalFoods":{"north":[{"image":"/images/banner1.jpg","title":"Dưa hành","desc":"Món ăn giúp cân bằng hương vị trong mâm cỗ Tết."}],"central":[{"image":"/images/banner2.jpg","title":"Bánh tét","desc":"Hương vị đậm đà thường gặp ở miền Trung và miền Nam."}],"south":[{"image":"/images/banner3.jpg","title":"Canh khổ qua nhồi thịt","desc":"Món ăn gửi gắm mong muốn khó khăn qua đi."}]},"culturalMeaningsDocs":[{"icon":"✨","title":"Khởi đầu mới","desc":"Tết tượng trưng cho sự đổi mới, tái tạo và hy vọng.","colorClass":"highlight-red"},{"icon":"👨‍👩‍👧‍👦","title":"Đoàn viên gia đình","desc":"Đây là dịp sum họp thiêng liêng nhất trong năm của người Việt.","colorClass":"highlight-orange"},{"icon":"🙏","title":"Biết ơn tổ tiên","desc":"Tinh thần uống nước nhớ nguồn được thể hiện sâu sắc trong mỗi nghi thức đầu năm.","colorClass":"highlight-yellow"}],"interestingFactsDocs":[{"icon":"🧧","title":"Sắc đỏ may mắn","desc":"Màu đỏ xuất hiện dày đặc trong trang trí ngày Tết như biểu tượng của phúc lộc."},{"icon":"🎇","title":"Khoảnh khắc giao thừa","desc":"Nhiều người xem giao thừa là thời khắc quan trọng nhất để gửi gắm mong ước đầu năm."},{"icon":"🌸","title":"Hoa xuân ba miền","desc":"Miền Bắc chuộng hoa đào, miền Nam yêu hoa mai, tạo nên bản sắc xuân rất riêng."}],"galleryHero":"/images/festival_banner.jpg","galleryGrid":["/images/banner1.jpg","/images/banner2.jpg","/images/banner3.jpg","/images/anhtet1.PNG","/images/banner1.jpg","/images/banner2.jpg"],"inShortText":"Tết Nguyên Đán là lát cắt rõ nét nhất của văn hóa Việt Nam — nơi gia đình, ký ức tổ tiên và niềm hy vọng đầu năm giao hòa trong cùng một không khí lễ hội.","discoverMore":[{"image":"/images/banner3.jpg","title":"Món ăn ngày Tết","desc":"Tìm hiểu ý nghĩa văn hóa đằng sau các món ăn truyền thống trong dịp đầu năm."},{"image":"/images/anhtet1.PNG","title":"Phong tục đầu xuân","desc":"Khám phá những tập quán quen thuộc như lì xì, chúc Tết, xông đất và du xuân."},{"image":"/images/festival_banner.jpg","title":"Không khí đoàn viên","desc":"Cảm nhận chiều sâu cảm xúc và tinh thần gia đình trong những ngày Tết Việt."}],"labels":{"whatIsItTitle":"Tết Nguyên Đán là gì?","dateLabel":"Thời gian","locationLabel":"Địa điểm","participantsLabel":"Thành phần tham gia","celebrationTitle":"Tết Nguyên Đán được tổ chức như thế nào?","feelsLikeTitle":"Trải nghiệm không khí Tết","keyTraditionsTitle":"Những nét truyền thống nổi bật","traditionalFoodsTitle":"Ẩm thực gắn với Tết Nguyên Đán","traditionalFoodsSubtitle":"Những món ăn ngày Tết không chỉ ngon mà còn mang theo nhiều lớp ý nghĩa văn hóa.","northRegionLabel":"Miền Bắc","centralRegionLabel":"Miền Trung","southRegionLabel":"Miền Nam","culturalMeaningsTitle":"Ý nghĩa văn hóa","interestingFactsTitle":"Điều thú vị về Tết Nguyên Đán","galleryTitle":"Tết Nguyên Đán qua hình ảnh","inShortTitle":"Tóm lược","discoverMoreTitle":"Khám phá thêm về Tết Nguyên Đán"}}',
  HoatDong = 1, NgayCapNhat = SYSUTCDATETIME()
WHERE MaLeHoi = 'tet-nguyen-dan';
GO

