UPDATE dbo.LeHoi SET
  LoaiBanGhi='FESTIVAL',ThuTuHienThi=2,TieuDeVI=N'Tết Trung Thu',TieuDePhuVI=N'Lễ hội trăng rằm',ShortTitleVI=N'Trung Thu',
  MoTaNganVI=N'Lễ hội dành cho thiếu nhi với lồng đèn, múa lân, bánh trung thu và không khí sum họp gia đình.',
  HeroDescVI=N'Lễ hội trăng rằm gắn với ký ức tuổi thơ, lồng đèn và tinh thần đoàn viên.',ViTriVI=N'Toàn quốc',NgayLeVI=N'Rằm tháng Tám âm lịch',
  TagVI=N'Lễ hội lớn',TagColor='#d946ef',ImageUrl=N'/images/banner2.jpg',ImageAltVI=N'Tết Trung Thu',TimelineMonthVI=N'Tháng 9',TimelineSeasonVI=N'Mùa thu',TimelineImageUrl=N'/images/banner2.jpg',TimelineImageAltVI=N'Tết Trung Thu',TimelineColor='#d946ef',
  NoiDungJsonVI=N'{"whatIsItContext":["Tết Trung Thu là lễ hội trăng rằm gắn với tuổi thơ, lồng đèn, bánh nướng bánh dẻo và bầu không khí sum họp của gia đình Việt.","Không chỉ là ngày hội của thiếu nhi, Trung Thu còn là dịp để cộng đồng quây quần, ngắm trăng và tận hưởng vẻ đẹp của đêm hội mùa thu."],"quickFacts":{"date":"Rằm tháng Tám âm lịch","location":"Toàn quốc","participants":"Thiếu nhi, gia đình và cộng đồng"},"howItIsCelebrated":[{"phase":"Chuẩn bị","title":"Làm lồng đèn và bày cỗ trăng","desc":["Các gia đình chuẩn bị bánh trung thu, trái cây, đồ chơi và lồng đèn cho trẻ em.","Không gian phố phường và khu dân cư thường được trang trí rực rỡ để chờ đón đêm rằm."],"image":"/images/banner2.jpg","align":"left"},{"phase":"Đêm hội","title":"Rước đèn và múa lân","desc":["Trẻ em cầm lồng đèn đi rước trong tiếng trống múa lân náo nhiệt.","Những màn biểu diễn lân - sư - rồng tạo nên không khí vui tươi, rộn ràng và đầy ký ức."],"image":"/images/banner1.jpg","align":"right"},{"phase":"Sum họp","title":"Phá cỗ và ngắm trăng","desc":["Sau các hoạt động ngoài trời, nhiều gia đình cùng nhau phá cỗ, thưởng trà và ngắm trăng.","Khoảnh khắc này nhấn mạnh sự gắn kết gia đình và niềm vui trong đời sống cộng đồng."],"image":"/images/festival_banner.jpg","align":"left"}],"whatTetFeelsLike":{"leftText":["Đường phố: Lung linh ánh đèn, sắc màu giấy kiếng và tiếng trống lân vang vọng.","Không khí: Tươi sáng, rộn ràng và đầy háo hức của trẻ thơ trong đêm rằm.","Nhịp điệu: Vừa náo nhiệt ngoài phố, vừa ấm áp khi trở về phá cỗ cùng gia đình."],"rightText":["Biểu tượng: Mặt trăng tròn, lồng đèn, đầu lân và mâm cỗ là những hình ảnh quen thuộc nhất.","Cảm xúc: Là niềm vui tuổi thơ, sự sum vầy và cảm giác mùa thu chạm tới từng mái nhà.","Trải nghiệm: Trung Thu luôn là một trong những lễ hội dễ khơi gợi ký ức nhất của người Việt."],"image":"/images/banner2.jpg"},"keyTraditionsDocs":[{"image":"/images/banner2.jpg","title":"Rước đèn","desc":"Hoạt động gắn với tuổi thơ và niềm vui cộng đồng trong đêm rằm."},{"image":"/images/banner1.jpg","title":"Múa lân","desc":"Biểu diễn đường phố tạo nên sinh khí và sự náo nhiệt cho lễ hội."},{"image":"/images/festival_banner.jpg","title":"Phá cỗ trăng","desc":"Khoảnh khắc sum họp cùng bánh trái và ánh trăng tròn."}],"traditionalFoods":[{"image":"/images/banner2.jpg","title":"Bánh nướng","desc":"Một trong những hương vị đặc trưng nhất của mùa Trung Thu."},{"image":"/images/banner1.jpg","title":"Bánh dẻo","desc":"Loại bánh mềm, thơm, gắn liền với đêm hội trăng rằm."},{"image":"/images/festival_banner.jpg","title":"Mâm cỗ trăng","desc":"Trái cây, bánh kẹo được bày biện đẹp mắt cho đêm hội."}],"regionalFoods":{"north":[{"image":"/images/banner1.jpg","title":"Mâm cỗ truyền thống","desc":"Thường bày biện theo hình con vật, gắn với sự khéo léo và vui tươi."}],"central":[{"image":"/images/banner2.jpg","title":"Bánh Trung Thu địa phương","desc":"Nhiều vùng có cách làm bánh và thưởng trà mang dấu ấn riêng."}],"south":[{"image":"/images/festival_banner.jpg","title":"Đêm hội khu phố","desc":"Không khí cộng đồng sôi động với các món quà bánh thân thuộc."}]},"culturalMeaningsDocs":[{"icon":"🌕","title":"Biểu tượng đoàn viên","desc":"Trăng tròn là hình ảnh của sự sum họp và đầy đủ.","colorClass":"highlight-red"},{"icon":"🎎","title":"Không gian tuổi thơ","desc":"Trung Thu lưu giữ nhiều ký ức đẹp trong đời sống văn hóa Việt.","colorClass":"highlight-orange"},{"icon":"🏮","title":"Sáng tạo dân gian","desc":"Lồng đèn, múa lân và cách bày cỗ thể hiện tính thẩm mỹ cộng đồng.","colorClass":"highlight-yellow"}],"interestingFactsDocs":[{"icon":"🥮","title":"Bánh và trăng","desc":"Bánh Trung Thu luôn gắn với hình ảnh trăng tròn, biểu tượng cho viên mãn."},{"icon":"🦁","title":"Nhịp trống múa lân","desc":"Âm thanh múa lân là dấu hiệu không thể thiếu của đêm hội Trung Thu."},{"icon":"👨‍👩‍👧‍👦","title":"Từ tuổi thơ đến gia đình","desc":"Ngày nay Trung Thu vừa là lễ hội trẻ em vừa là dịp gia đình sum họp."}],"galleryHero":"/images/banner2.jpg","galleryGrid":["/images/banner2.jpg","/images/banner1.jpg","/images/festival_banner.jpg","/images/banner3.jpg","/images/banner2.jpg","/images/banner1.jpg"],"inShortText":"Tết Trung Thu là đêm hội của ánh trăng, lồng đèn và tuổi thơ — nơi niềm vui cộng đồng gặp gỡ sự ấm áp gia đình trong một không khí rất Việt Nam.","discoverMore":[{"image":"/images/banner2.jpg","title":"Lồng đèn Trung Thu","desc":"Khám phá những kiểu đèn truyền thống và ý nghĩa biểu tượng của chúng."},{"image":"/images/banner1.jpg","title":"Múa lân ngày rằm","desc":"Tìm hiểu vì sao tiếng trống lân luôn là linh hồn của đêm hội Trung Thu."},{"image":"/images/festival_banner.jpg","title":"Bánh và mâm cỗ trăng","desc":"Những hương vị và cách bày biện làm nên bản sắc của mùa Trung Thu Việt Nam."}],"labels":{"whatIsItTitle":"Tết Trung Thu là gì?","dateLabel":"Thời gian","locationLabel":"Địa điểm","participantsLabel":"Thành phần tham gia","celebrationTitle":"Tết Trung Thu được tổ chức như thế nào?","feelsLikeTitle":"Trải nghiệm không khí Trung Thu","keyTraditionsTitle":"Những nét truyền thống nổi bật","traditionalFoodsTitle":"Ẩm thực gắn với Tết Trung Thu","traditionalFoodsSubtitle":"Bánh, trà và mâm cỗ trăng góp phần làm nên ký ức đặc biệt của đêm rằm.","northRegionLabel":"Miền Bắc","centralRegionLabel":"Miền Trung","southRegionLabel":"Miền Nam","culturalMeaningsTitle":"Ý nghĩa văn hóa","interestingFactsTitle":"Điều thú vị về Tết Trung Thu","galleryTitle":"Tết Trung Thu qua hình ảnh","inShortTitle":"Tóm lược","discoverMoreTitle":"Khám phá thêm về Tết Trung Thu"}}',
  HoatDong=1,NgayCapNhat=SYSUTCDATETIME()
WHERE MaLeHoi='tet-trung-thu';
GO

UPDATE dbo.LeHoi SET
  LoaiBanGhi='FESTIVAL',ThuTuHienThi=3,TieuDeVI=N'Giỗ Tổ Hùng Vương',TieuDePhuVI=N'Lễ tưởng niệm các Vua Hùng',ShortTitleVI=N'Đền Hùng',MoTaNganVI=N'Ngày lễ lớn để tưởng nhớ các Vua Hùng, gắn với đạo lý uống nước nhớ nguồn và bản sắc dân tộc.',HeroDescVI=N'Lễ hội tưởng niệm nguồn cội dân tộc với nghi thức dâng hương và sinh hoạt cộng đồng.',ViTriVI=N'Phú Thọ',NgayLeVI=N'Mùng 10 tháng 3 âm lịch',TagVI=N'Văn hóa',TagColor='#ea580c',ImageUrl=N'/images/giotohungvuong1.PNG',ImageAltVI=N'Giỗ Tổ Hùng Vương',TimelineMonthVI=N'Tháng 4',TimelineSeasonVI=N'Mùa xuân',TimelineImageUrl=N'/images/giotohungvuong1.PNG',TimelineImageAltVI=N'Giỗ Tổ Hùng Vương',TimelineColor='#ea580c',
  NoiDungJsonVI=N'{"whatIsItContext":["Giỗ Tổ Hùng Vương là ngày lễ tưởng niệm các Vua Hùng, những người được xem là thủy tổ của dân tộc Việt Nam.","Lễ hội vừa mang tính quốc gia, vừa đậm chất tín ngưỡng dân gian với nghi thức dâng hương, rước lễ và sinh hoạt cộng đồng."],"quickFacts":{"date":"Mùng 10 tháng 3 âm lịch","location":"Đền Hùng, Phú Thọ","participants":"Người dân cả nước, du khách và cộng đồng địa phương"},"howItIsCelebrated":[{"phase":"Hướng về cội nguồn","title":"Chuẩn bị lễ vật và hành hương","desc":["Nhiều đoàn người từ khắp nơi đổ về Phú Thọ để tham dự các hoạt động tưởng niệm.","Lễ vật dâng cúng thường được chuẩn bị trang trọng, thể hiện lòng biết ơn với tổ tiên dân tộc."],"image":"/images/giotohungvuong1.PNG","align":"left"},{"phase":"Chính lễ","title":"Dâng hương tưởng niệm","desc":["Nghi thức dâng hương tại khu di tích Đền Hùng là trung tâm của ngày lễ này.","Không gian lễ nghi trang nghiêm nhấn mạnh đạo lý uống nước nhớ nguồn và ý thức cộng đồng dân tộc."],"image":"/images/banner1.jpg","align":"right"},{"phase":"Phần hội","title":"Hoạt động văn hóa và dân gian","desc":["Bên cạnh phần lễ là nhiều hoạt động như hát xoan, trò chơi dân gian và sinh hoạt cộng đồng.","Những hoạt động này giúp ngày Giỗ Tổ vừa thiêng liêng vừa gần gũi với đời sống văn hóa dân gian."],"image":"/images/banner3.jpg","align":"left"}],"whatTetFeelsLike":{"leftText":["Không gian: Trang nghiêm, đông đảo và thấm đẫm tinh thần hướng về cội nguồn.","Âm thanh: Tiếng nhạc lễ, lời xướng nghi thức và nhịp sinh hoạt của đoàn người hành hương.","Cảnh sắc: Núi Nghĩa Lĩnh, đền đài và sắc cờ tạo nên cảm giác thiêng liêng rất đặc biệt."],"rightText":["Cảm xúc: Tự hào, biết ơn và ý thức rõ rệt về lịch sử chung của dân tộc.","Biểu tượng: Nén hương, bánh chưng bánh dày và nghi lễ dâng cúng là những hình ảnh tiêu biểu.","Trải nghiệm: Đây là một trong những lễ hội khiến người tham dự cảm nhận rõ nhất tinh thần quốc gia - cộng đồng."],"image":"/images/giotohungvuong1.PNG"},"keyTraditionsDocs":[{"image":"/images/giotohungvuong1.PNG","title":"Dâng hương","desc":"Nghi thức trung tâm thể hiện lòng tri ân với các Vua Hùng."},{"image":"/images/banner1.jpg","title":"Hành hương về Đền Hùng","desc":"Hành trình biểu tượng của tinh thần hướng về cội nguồn dân tộc."},{"image":"/images/banner3.jpg","title":"Hát xoan và sinh hoạt dân gian","desc":"Những giá trị văn hóa phi vật thể gắn với không gian lễ hội Đền Hùng."}],"traditionalFoods":[{"image":"/images/banner1.jpg","title":"Bánh chưng","desc":"Món bánh biểu tượng gắn với truyền thuyết thời Hùng Vương."},{"image":"/images/banner2.jpg","title":"Bánh dày","desc":"Biểu tượng cho trời đất và ý thức cội nguồn trong văn hóa Việt."},{"image":"/images/banner3.jpg","title":"Lễ vật dân gian","desc":"Những sản vật địa phương được chuẩn bị như lời dâng kính tổ tiên."}],"regionalFoods":{"north":[{"image":"/images/banner1.jpg","title":"Bánh chưng - bánh dày","desc":"Hình ảnh quen thuộc nhất khi nhắc tới ngày Giỗ Tổ."}],"central":[{"image":"/images/banner2.jpg","title":"Lễ vật hành hương","desc":"Người từ nhiều vùng vẫn mang theo sản vật quê hương để dâng lễ."}],"south":[{"image":"/images/banner3.jpg","title":"Tinh thần hướng về đất Tổ","desc":"Ngày lễ được tưởng nhớ rộng khắp, vượt qua ranh giới vùng miền."}]},"culturalMeaningsDocs":[{"icon":"🏛️","title":"Khẳng định cội nguồn dân tộc","desc":"Giỗ Tổ nhắc nhớ về nguồn gốc chung và lịch sử dựng nước.","colorClass":"highlight-red"},{"icon":"🙏","title":"Biết ơn tiền nhân","desc":"Lòng tri ân với tổ tiên là lớp ý nghĩa sâu nhất của ngày lễ này.","colorClass":"highlight-orange"},{"icon":"🤝","title":"Củng cố tinh thần cộng đồng","desc":"Ngày lễ tạo ra sự kết nối giữa cá nhân, gia đình và quốc gia.","colorClass":"highlight-yellow"}],"interestingFactsDocs":[{"icon":"📜","title":"Ngày quốc lễ","desc":"Giỗ Tổ Hùng Vương là một ngày nghỉ lễ chính thức trên phạm vi cả nước."},{"icon":"🎶","title":"Không gian hát xoan","desc":"Phú Thọ còn nổi tiếng với hát xoan, loại hình gắn bó chặt chẽ với tín ngưỡng thờ cúng Hùng Vương."},{"icon":"🥁","title":"Phần hội đa dạng","desc":"Từ rước kiệu đến trò chơi dân gian, phần hội tạo nên sức sống cộng đồng cho ngày lễ."}],"galleryHero":"/images/giotohungvuong1.PNG","galleryGrid":["/images/giotohungvuong1.PNG","/images/banner1.jpg","/images/banner2.jpg","/images/banner3.jpg","/images/giotohungvuong1.PNG","/images/banner1.jpg"],"inShortText":"Giỗ Tổ Hùng Vương là ngày lễ thiêng liêng nhắc người Việt nhớ về cội nguồn chung, nuôi dưỡng tinh thần biết ơn và ý thức cộng đồng dân tộc.","discoverMore":[{"image":"/images/giotohungvuong1.PNG","title":"Đền Hùng và không gian linh thiêng","desc":"Tìm hiểu vì sao Phú Thọ trở thành điểm hội tụ ký ức cội nguồn dân tộc."},{"image":"/images/banner1.jpg","title":"Truyền thuyết Hùng Vương","desc":"Khám phá những câu chuyện gắn với buổi đầu dựng nước trong ký ức người Việt."},{"image":"/images/banner3.jpg","title":"Hát xoan và phần hội","desc":"Những thực hành văn hóa dân gian góp phần làm nên sức sống của ngày Giỗ Tổ."}],"labels":{"whatIsItTitle":"Giỗ Tổ Hùng Vương là gì?","dateLabel":"Thời gian","locationLabel":"Địa điểm","participantsLabel":"Thành phần tham gia","celebrationTitle":"Giỗ Tổ Hùng Vương được tổ chức như thế nào?","feelsLikeTitle":"Trải nghiệm không khí Giỗ Tổ Hùng Vương","keyTraditionsTitle":"Những nét truyền thống nổi bật","traditionalFoodsTitle":"Ẩm thực và lễ vật trong ngày Giỗ Tổ","traditionalFoodsSubtitle":"Lễ vật dâng cúng và món ăn truyền thống góp phần thể hiện tinh thần hướng về cội nguồn.","northRegionLabel":"Miền Bắc","centralRegionLabel":"Miền Trung","southRegionLabel":"Miền Nam","culturalMeaningsTitle":"Ý nghĩa văn hóa","interestingFactsTitle":"Điều thú vị về Giỗ Tổ Hùng Vương","galleryTitle":"Giỗ Tổ Hùng Vương qua hình ảnh","inShortTitle":"Tóm lược","discoverMoreTitle":"Khám phá thêm về Giỗ Tổ Hùng Vương"}}',HoatDong=1,NgayCapNhat=SYSUTCDATETIME()
WHERE MaLeHoi='gio-to-hung-vuong';
GO

UPDATE dbo.LeHoi SET
  LoaiBanGhi='FESTIVAL',ThuTuHienThi=4,TieuDeVI=N'Festival Huế',TieuDePhuVI=N'Lễ hội di sản cố đô',ShortTitleVI=N'Huế',MoTaNganVI=N'Sự kiện văn hóa quy mô lớn tái hiện vẻ đẹp cung đình, nghệ thuật trình diễn và di sản cố đô Huế.',HeroDescVI=N'Lễ hội văn hóa kết nối di sản cung đình, nghệ thuật đương đại và trải nghiệm cộng đồng.',ViTriVI=N'Thành phố Huế',NgayLeVI=N'Theo mùa tổ chức của kỳ lễ hội',TagVI=N'Văn hóa',TagColor='#10b981',ImageUrl=N'/images/festival_hue.png',ImageAltVI=N'Festival Huế',TimelineMonthVI=N'Tháng 6',TimelineSeasonVI=N'Mùa hạ',TimelineImageUrl=N'/images/festival_hue.png',TimelineImageAltVI=N'Festival Huế',TimelineColor='#10b981',
  NoiDungJsonVI=N'{"whatIsItContext":["Festival Huế là sự kiện văn hóa lớn tôn vinh di sản cố đô, kết nối nghệ thuật cung đình, trình diễn đương đại và không gian sống của thành phố Huế.","Lễ hội này giúp du khách cảm nhận rõ chiều sâu của di sản triều Nguyễn trong một bối cảnh mở, giàu tính thị giác và trải nghiệm cộng đồng."],"quickFacts":{"date":"Theo mùa tổ chức của kỳ lễ hội","location":"Thành phố Huế","participants":"Người dân, nghệ sĩ, du khách trong và ngoài nước"},"howItIsCelebrated":[{"phase":"Chuẩn bị","title":"Trang hoàng không gian cố đô","desc":["Nhiều tuyến phố, sân khấu và điểm di sản được chuẩn bị để đón các chương trình nghệ thuật.","Thành phố Huế bước vào mùa lễ hội với vẻ đẹp trang trọng, duyên dáng và giàu chất di sản."],"image":"/images/festival_hue.png","align":"left"},{"phase":"Trình diễn","title":"Nghệ thuật cung đình và đường phố","desc":["Các chương trình biểu diễn có thể diễn ra từ không gian cung đình đến các sân khấu ngoài trời.","Sự kết hợp giữa truyền thống và hiện đại tạo nên bản sắc riêng của Festival Huế."],"image":"/images/banner1.jpg","align":"right"},{"phase":"Trải nghiệm","title":"Khám phá di sản qua nhiều lớp cảm xúc","desc":["Du khách không chỉ xem biểu diễn mà còn hòa mình vào nhịp sống, ẩm thực và cảnh quan của Huế.","Festival trở thành cánh cửa giúp công chúng tiếp cận di sản theo cách sống động và gần gũi hơn."],"image":"/images/banner2.jpg","align":"left"}],"whatTetFeelsLike":{"leftText":["Không gian: Vẻ đẹp trầm mặc của Huế hòa cùng ánh sáng, sân khấu và sắc màu lễ hội.","Âm thanh: Nhã nhạc, trình diễn đường phố và những tiết mục đa dạng vang lên giữa không gian di sản.","Nhịp điệu: Vừa thanh lịch, sâu lắng vừa sôi động nhờ sự giao thoa giữa nghệ thuật và đời sống đô thị."],"rightText":["Cảm xúc: Là sự ngưỡng mộ, thư thái và tò mò trước vẻ đẹp của một cố đô sống cùng hiện tại.","Biểu tượng: Áo dài, thành quách, sân khấu ngoài trời và nhịp biểu diễn là các dấu ấn nổi bật.","Trải nghiệm: Festival Huế khiến di sản không đứng yên mà trở thành trải nghiệm đang diễn ra trước mắt người xem."],"image":"/images/festival_hue.png"},"keyTraditionsDocs":[{"image":"/images/festival_hue.png","title":"Không gian di sản cố đô","desc":"Các điểm di sản trở thành sân khấu giàu chiều sâu lịch sử và thẩm mỹ."},{"image":"/images/banner1.jpg","title":"Nghệ thuật cung đình","desc":"Những lớp di sản triều Nguyễn được tái hiện qua trình diễn và nghi thức."},{"image":"/images/banner2.jpg","title":"Lễ hội cộng đồng đương đại","desc":"Festival Huế cũng là nơi gặp gỡ của nghệ thuật hiện đại và công chúng hôm nay."}],"traditionalFoods":[{"image":"/images/banner1.jpg","title":"Ẩm thực Huế","desc":"Các món ăn địa phương góp phần hoàn chỉnh trải nghiệm văn hóa trong mùa festival."},{"image":"/images/banner2.jpg","title":"Món cung đình cách tân","desc":"Một số không gian ẩm thực gợi lại tinh thần ẩm thực triều Nguyễn."},{"image":"/images/festival_hue.png","title":"Hương vị cố đô","desc":"Ẩm thực giúp du khách cảm nhận sâu hơn nhịp sống và tính cách của Huế."}],"regionalFoods":{"north":[{"image":"/images/banner1.jpg","title":"Góc nhìn từ di sản cả nước","desc":"Festival Huế thu hút du khách từ nhiều miền đến trải nghiệm."}],"central":[{"image":"/images/festival_hue.png","title":"Hương vị xứ Huế","desc":"Ẩm thực miền Trung góp phần làm nên phong vị riêng của mùa lễ hội."}],"south":[{"image":"/images/banner2.jpg","title":"Giao lưu văn hóa","desc":"Sự hiện diện của du khách và nghệ sĩ từ khắp nơi làm phong phú không gian sự kiện."}]},"culturalMeaningsDocs":[{"icon":"🏯","title":"Làm sống dậy di sản","desc":"Festival Huế giúp di sản cố đô bước vào đời sống đương đại một cách sinh động.","colorClass":"highlight-red"},{"icon":"🎭","title":"Kết nối nghệ thuật và cộng đồng","desc":"Sự kiện tạo ra không gian gặp gỡ giữa nghệ sĩ, người dân và du khách.","colorClass":"highlight-orange"},{"icon":"🌏","title":"Lan tỏa hình ảnh Huế","desc":"Festival là cầu nối để văn hóa Huế được giới thiệu rộng rãi hơn ra thế giới.","colorClass":"highlight-yellow"}],"interestingFactsDocs":[{"icon":"🎼","title":"Nhã nhạc và di sản cung đình","desc":"Huế luôn gắn với những lớp di sản âm nhạc và nghi lễ cung đình đặc sắc."},{"icon":"👘","title":"Áo dài trong không gian lễ hội","desc":"Hình ảnh áo dài xuất hiện nhiều, làm nổi bật vẻ thanh lịch và chiều sâu văn hóa Huế."},{"icon":"📸","title":"Festival giàu tính thị giác","desc":"Đây là một trong những sự kiện văn hóa tạo ra nhiều hình ảnh biểu tượng nhất của miền Trung."}],"galleryHero":"/images/festival_hue.png","galleryGrid":["/images/festival_hue.png","/images/banner1.jpg","/images/banner2.jpg","/images/banner3.jpg","/images/festival_hue.png","/images/banner1.jpg"],"inShortText":"Festival Huế là nơi di sản cố đô được tái hiện bằng nhiều hình thức nghệ thuật, giúp công chúng cảm nhận Huế như một không gian văn hóa đang sống động trong hiện tại.","discoverMore":[{"image":"/images/festival_hue.png","title":"Di sản cố đô trong mùa festival","desc":"Khám phá cách các điểm di sản trở thành không gian biểu diễn và trải nghiệm văn hóa."},{"image":"/images/banner1.jpg","title":"Nghệ thuật cung đình Huế","desc":"Tìm hiểu những lớp di sản thẩm mỹ và nghi lễ góp phần làm nên nét riêng của Huế."},{"image":"/images/banner2.jpg","title":"Huế trong mắt du khách","desc":"Cảm nhận thành phố qua âm nhạc, ẩm thực, kiến trúc và nhịp sống lễ hội."}],"labels":{"whatIsItTitle":"Festival Huế là gì?","dateLabel":"Thời gian","locationLabel":"Địa điểm","participantsLabel":"Thành phần tham gia","celebrationTitle":"Festival Huế diễn ra như thế nào?","feelsLikeTitle":"Trải nghiệm không khí Festival Huế","keyTraditionsTitle":"Những nét nổi bật của festival","traditionalFoodsTitle":"Ẩm thực trong mùa Festival Huế","traditionalFoodsSubtitle":"Ẩm thực góp phần làm đầy thêm trải nghiệm di sản và nhịp sống cố đô.","northRegionLabel":"Miền Bắc","centralRegionLabel":"Miền Trung","southRegionLabel":"Miền Nam","culturalMeaningsTitle":"Ý nghĩa văn hóa","interestingFactsTitle":"Điều thú vị về Festival Huế","galleryTitle":"Festival Huế qua hình ảnh","inShortTitle":"Tóm lược","discoverMoreTitle":"Khám phá thêm về Festival Huế"}}',HoatDong=1,NgayCapNhat=SYSUTCDATETIME()
WHERE MaLeHoi='festival-hue';
GO

UPDATE dbo.LeHoi SET
  LoaiBanGhi='FESTIVAL',ThuTuHienThi=5,TieuDeVI=N'Lễ hội Gầu Tào',TieuDePhuVI=N'Lễ hội cầu phúc của người H''Mông',ShortTitleVI=N'Gầu Tào',MoTaNganVI=N'Lễ hội mùa xuân của người H''Mông, cầu bình an, sức khỏe và mùa màng thuận lợi cho cộng đồng.',HeroDescVI=N'Lễ hội cộng đồng giàu bản sắc vùng cao, gắn với khèn, trò chơi dân gian và lời cầu chúc đầu năm.',ViTriVI=N'Một số tỉnh miền núi phía Bắc',NgayLeVI=N'Thường diễn ra vào đầu xuân',TagVI=N'Dân tộc',TagColor='#8b5cf6',ImageUrl=N'/images/hmong_festival_gau_tao_1775575986843.png',ImageAltVI=N'Lễ hội Gầu Tào',TimelineMonthVI=N'Tháng 1',TimelineSeasonVI=N'Mùa xuân',TimelineImageUrl=N'/images/hmong_festival_gau_tao_1775575986843.png',TimelineImageAltVI=N'Lễ hội Gầu Tào',TimelineColor='#8b5cf6',
  NoiDungJsonVI=N'{"whatIsItContext":["Lễ hội Gầu Tào là lễ hội mùa xuân đặc sắc của người H''Mông, thường gắn với lời cầu chúc về sức khỏe, bình an và mùa màng thuận lợi.","Đây là dịp cộng đồng gặp gỡ, vui chơi, trình diễn âm nhạc, thi tài và khẳng định bản sắc văn hóa vùng cao."],"quickFacts":{"date":"Thường diễn ra vào đầu xuân","location":"Một số tỉnh miền núi phía Bắc","participants":"Cộng đồng H''Mông và du khách"},"howItIsCelebrated":[{"phase":"Chuẩn bị","title":"Dựng cây nêu và chuẩn bị không gian hội","desc":["Không gian tổ chức lễ hội được chọn kỹ, thường gắn với triền đồi hoặc bãi đất rộng của bản làng.","Cây nêu và các vật phẩm tượng trưng được dựng lên như dấu hiệu mở đầu mùa hội."],"image":"/images/hmong_festival_gau_tao_1775575986843.png","align":"left"},{"phase":"Nghi lễ","title":"Cầu phúc, cầu an và cầu mùa","desc":["Phần nghi lễ thể hiện mong muốn về sức khỏe, con cháu, chăn nuôi và mùa màng thuận lợi.","Đó cũng là lúc cộng đồng khẳng định mối gắn kết với tổ tiên, thiên nhiên và đời sống bản làng."],"image":"/images/banner1.jpg","align":"right"},{"phase":"Phần hội","title":"Âm nhạc, trò chơi và gặp gỡ cộng đồng","desc":["Sau phần lễ là các hoạt động vui chơi, múa hát, thổi khèn và giao lưu giữa các nhóm người tham dự.","Không khí ấy làm cho Gầu Tào trở thành một trong những lễ hội mùa xuân giàu sinh khí nhất vùng cao."],"image":"/images/banner2.jpg","align":"left"}],"whatTetFeelsLike":{"leftText":["Không gian: Mùa xuân vùng cao mở ra với sắc trời trong, trang phục rực rỡ và tiếng khèn vang vọng.","Âm thanh: Khèn H''Mông, tiếng gọi bạn, tiếng cười và trò chơi làm bừng lên sinh khí bản làng.","Nhịp sống: Vừa linh thiêng trong nghi lễ, vừa phóng khoáng trong sinh hoạt hội xuân."],"rightText":["Con người: Người tham dự đến trong những bộ trang phục đẹp nhất, mang theo niềm vui đầu năm.","Cảm xúc: Đó là cảm giác phấn khởi, tự hào và gắn kết của cộng đồng giữa núi rừng.","Trải nghiệm: Gầu Tào cho thấy lễ hội không chỉ để tưởng niệm mà còn để sống, vui và khẳng định bản sắc."],"image":"/images/hmong_festival_gau_tao_1775575986843.png"},"keyTraditionsDocs":[{"image":"/images/hmong_festival_gau_tao_1775575986843.png","title":"Cây nêu ngày hội","desc":"Biểu tượng mở đầu cho không gian lễ hội và ước vọng đầu năm."},{"image":"/images/banner1.jpg","title":"Tiếng khèn H''Mông","desc":"Âm nhạc giữ vai trò quan trọng trong sinh hoạt và biểu cảm cộng đồng."},{"image":"/images/banner2.jpg","title":"Trò chơi dân gian vùng cao","desc":"Các hoạt động hội giúp kết nối cộng đồng và tạo nên sức sống mùa xuân."}],"traditionalFoods":[{"image":"/images/banner1.jpg","title":"Món ăn ngày hội","desc":"Những món ăn bản địa giúp gắn kết mọi người trong dịp lễ đầu xuân."},{"image":"/images/banner2.jpg","title":"Rượu ngô","desc":"Thức uống thường xuất hiện trong những cuộc vui cộng đồng ở vùng cao."},{"image":"/images/hmong_festival_gau_tao_1775575986843.png","title":"Ẩm thực bản làng","desc":"Hương vị mộc mạc nhưng đậm đà của miền núi góp phần tạo nên không khí lễ hội."}],"regionalFoods":{"north":[{"image":"/images/hmong_festival_gau_tao_1775575986843.png","title":"Hương vị vùng cao","desc":"Các món ăn gắn với khí hậu, nương rẫy và nhịp sống miền núi."}],"central":[{"image":"/images/banner1.jpg","title":"Góc nhìn giao lưu vùng miền","desc":"Du khách từ nơi khác có thể tiếp cận ẩm thực vùng cao qua không gian lễ hội."}],"south":[{"image":"/images/banner2.jpg","title":"Trải nghiệm khác biệt","desc":"Gầu Tào tạo ấn tượng mạnh nhờ không khí vùng cao rất riêng biệt."}]},"culturalMeaningsDocs":[{"icon":"🌱","title":"Cầu phúc đầu năm","desc":"Lễ hội gửi gắm ước vọng về bình an, sức khỏe và mùa màng thuận lợi.","colorClass":"highlight-red"},{"icon":"🎶","title":"Khẳng định bản sắc H''Mông","desc":"Âm nhạc, trang phục và không gian cộng đồng đều góp phần làm rõ bản sắc văn hóa.","colorClass":"highlight-orange"},{"icon":"🤝","title":"Kết nối cộng đồng vùng cao","desc":"Gầu Tào là dịp để gặp gỡ, giao lưu và củng cố quan hệ trong bản làng.","colorClass":"highlight-yellow"}],"interestingFactsDocs":[{"icon":"🎋","title":"Cây nêu lễ hội","desc":"Một biểu tượng quen thuộc gắn với mở đầu mùa hội và lời cầu chúc đầu năm."},{"icon":"🪗","title":"Vai trò của tiếng khèn","desc":"Khèn vừa là nhạc cụ, vừa là phương tiện biểu đạt cảm xúc trong không gian hội."},{"icon":"👘","title":"Trang phục ngày hội","desc":"Sắc màu trang phục tạo nên một trong những ấn tượng thị giác mạnh nhất của Gầu Tào."}],"galleryHero":"/images/hmong_festival_gau_tao_1775575986843.png","galleryGrid":["/images/hmong_festival_gau_tao_1775575986843.png","/images/banner1.jpg","/images/banner2.jpg","/images/banner3.jpg","/images/hmong_festival_gau_tao_1775575986843.png","/images/banner1.jpg"],"inShortText":"Lễ hội Gầu Tào là mùa hội của lời cầu phúc, của âm nhạc vùng cao và tinh thần cộng đồng H''Mông được thể hiện mạnh mẽ giữa không gian núi rừng đầu xuân.","discoverMore":[{"image":"/images/hmong_festival_gau_tao_1775575986843.png","title":"Nghi lễ cầu phúc đầu năm","desc":"Tìm hiểu ý nghĩa của phần lễ trong đời sống cộng đồng H''Mông."},{"image":"/images/banner1.jpg","title":"Tiếng khèn và không gian hội","desc":"Khám phá vai trò của âm nhạc trong việc tạo nên linh hồn lễ hội Gầu Tào."},{"image":"/images/banner2.jpg","title":"Sắc màu bản làng mùa xuân","desc":"Trang phục, trò chơi và gặp gỡ cộng đồng làm nên vẻ đẹp riêng của mùa hội vùng cao."}],"labels":{"whatIsItTitle":"Lễ hội Gầu Tào là gì?","dateLabel":"Thời gian","locationLabel":"Địa điểm","participantsLabel":"Thành phần tham gia","celebrationTitle":"Lễ hội Gầu Tào diễn ra như thế nào?","feelsLikeTitle":"Trải nghiệm không khí Gầu Tào","keyTraditionsTitle":"Những nét truyền thống nổi bật","traditionalFoodsTitle":"Ẩm thực trong mùa hội Gầu Tào","traditionalFoodsSubtitle":"Hương vị bản địa góp phần tạo nên sự ấm áp và gắn kết trong không gian hội xuân.","northRegionLabel":"Miền Bắc","centralRegionLabel":"Miền Trung","southRegionLabel":"Miền Nam","culturalMeaningsTitle":"Ý nghĩa văn hóa","interestingFactsTitle":"Điều thú vị về lễ hội Gầu Tào","galleryTitle":"Lễ hội Gầu Tào qua hình ảnh","inShortTitle":"Tóm lược","discoverMoreTitle":"Khám phá thêm về lễ hội Gầu Tào"}}',HoatDong=1,NgayCapNhat=SYSUTCDATETIME()
WHERE MaLeHoi='gau-tao';
GO

UPDATE dbo.LeHoi SET
  LoaiBanGhi='FESTIVAL',ThuTuHienThi=6,TieuDeVI=N'Lễ hội Katê',TieuDePhuVI=N'Lễ hội đặc sắc của người Chăm',ShortTitleVI=N'Katê',MoTaNganVI=N'Lễ hội lớn của người Chăm nhằm tưởng nhớ tổ tiên, thần linh và tôn vinh bản sắc văn hóa cộng đồng.',HeroDescVI=N'Lễ hội gắn với đền tháp, âm nhạc, trang phục và nghi thức cộng đồng của người Chăm.',ViTriVI=N'Ninh Thuận - Bình Thuận',NgayLeVI=N'Theo lịch Chăm, thường vào mùa thu',TagVI=N'Dân tộc',TagColor='#f59e0b',ImageUrl=N'/images/cham.jpg',ImageAltVI=N'Lễ hội Katê',TimelineMonthVI=N'Tháng 10',TimelineSeasonVI=N'Mùa thu',TimelineImageUrl=N'/images/cham.jpg',TimelineImageAltVI=N'Lễ hội Katê',TimelineColor='#f59e0b',
  NoiDungJsonVI=N'{"whatIsItContext":["Lễ hội Katê là một trong những lễ hội quan trọng nhất của người Chăm, gắn với việc tưởng nhớ tổ tiên, các vị thần và những nhân vật có công với cộng đồng.","Lễ hội thường diễn ra trong không gian đền tháp, nơi nghi lễ, âm nhạc, trang phục và sinh hoạt cộng đồng hòa quyện thành một chỉnh thể đặc sắc."],"quickFacts":{"date":"Theo lịch Chăm, thường vào mùa thu","location":"Ninh Thuận - Bình Thuận","participants":"Cộng đồng Chăm, cư dân địa phương và du khách"},"howItIsCelebrated":[{"phase":"Chuẩn bị","title":"Làm lễ tại gia đình và cộng đồng","desc":["Nhiều gia đình chuẩn bị trang phục, lễ vật và sắp xếp các hoạt động liên quan đến mùa Katê.","Không khí lễ hội lan tỏa từ gia đình ra cộng đồng, tạo nên sự chờ đón rất rõ nét."],"image":"/images/cham.jpg","align":"left"},{"phase":"Chính lễ","title":"Nghi thức tại đền tháp","desc":["Các nghi thức diễn ra tại những cụm tháp Chăm với sự hiện diện của chức sắc, cộng đồng và người tham dự.","Không gian này làm nổi bật chiều sâu lịch sử, tín ngưỡng và thẩm mỹ của văn hóa Chăm."],"image":"/images/banner1.jpg","align":"right"},{"phase":"Sinh hoạt hội","title":"Âm nhạc, múa và giao lưu cộng đồng","desc":["Sau phần nghi lễ là âm nhạc, điệu múa và các hoạt động cộng đồng giàu sắc màu.","Katê vì thế vừa là lễ tưởng niệm vừa là ngày hội văn hóa sống động của người Chăm."],"image":"/images/banner2.jpg","align":"left"}],"whatTetFeelsLike":{"leftText":["Không gian: Tháp Chăm, trang phục rực rỡ và âm thanh lễ hội tạo nên một cảnh quan rất riêng.","Âm thanh: Trống, kèn và nhạc cụ truyền thống làm bầu không khí trở nên thiêng liêng nhưng vẫn tràn đầy sức sống.","Nhịp điệu: Chuyển từ nghi lễ trang trọng sang sinh hoạt hội giàu cảm xúc cộng đồng."],"rightText":["Con người: Người tham dự mang theo niềm tự hào và sự gắn bó sâu sắc với di sản Chăm.","Cảm xúc: Katê đem lại cảm giác vừa linh thiêng vừa rực rỡ, như một ký ức văn hóa đang hiện diện trước mắt.","Trải nghiệm: Đây là dịp hiếm có để cảm nhận văn hóa Chăm trong không gian nguyên bản và giàu biểu tượng."],"image":"/images/cham.jpg"},"keyTraditionsDocs":[{"image":"/images/cham.jpg","title":"Không gian tháp Chăm","desc":"Đền tháp là trung tâm thiêng liêng của lễ hội Katê."},{"image":"/images/banner1.jpg","title":"Trang phục lễ hội","desc":"Sắc màu trang phục góp phần tạo nên diện mạo nổi bật của ngày hội."},{"image":"/images/banner2.jpg","title":"Âm nhạc và múa nghi lễ","desc":"Những yếu tố làm sống dậy không khí cộng đồng và bản sắc Chăm."}],"traditionalFoods":[{"image":"/images/cham.jpg","title":"Món ăn cộng đồng","desc":"Ẩm thực ngày hội tạo nên bầu không khí sẻ chia và quây quần."},{"image":"/images/banner1.jpg","title":"Lễ vật dâng cúng","desc":"Một phần quan trọng trong nghi thức tưởng niệm và tri ân."},{"image":"/images/banner2.jpg","title":"Hương vị vùng duyên hải","desc":"Ẩm thực địa phương gắn với không gian sống của người Chăm."}],"regionalFoods":{"north":[{"image":"/images/banner1.jpg","title":"Trải nghiệm vùng khác","desc":"Katê đem đến cho du khách ngoài miền Trung một cảm nhận văn hóa rất khác biệt."}],"central":[{"image":"/images/cham.jpg","title":"Hương vị xứ Chăm","desc":"Ẩm thực địa phương góp phần làm rõ bản sắc vùng đất Ninh Thuận - Bình Thuận."}],"south":[{"image":"/images/banner2.jpg","title":"Sự lan tỏa văn hóa","desc":"Nhiều du khách từ phương Nam tìm đến Katê để trải nghiệm văn hóa Chăm."}]},"culturalMeaningsDocs":[{"icon":"🛕","title":"Tưởng nhớ tổ tiên và thần linh","desc":"Katê là dịp thể hiện chiều sâu tâm linh trong đời sống cộng đồng Chăm.","colorClass":"highlight-red"},{"icon":"🎼","title":"Bảo tồn di sản Chăm","desc":"Âm nhạc, tháp, trang phục và nghi lễ góp phần giữ gìn bản sắc cộng đồng.","colorClass":"highlight-orange"},{"icon":"🌾","title":"Gắn kết cộng đồng vùng duyên hải","desc":"Lễ hội tạo nên nhịp sinh hoạt chung, củng cố ký ức và sự gắn bó cộng đồng.","colorClass":"highlight-yellow"}],"interestingFactsDocs":[{"icon":"🏺","title":"Không gian tháp cổ","desc":"Katê thường gắn với các tháp Chăm, làm nổi bật chiều sâu lịch sử và kiến trúc."},{"icon":"🥁","title":"Nhạc cụ truyền thống","desc":"Âm nhạc giữ vai trò rất quan trọng trong việc tạo nên khí sắc lễ hội."},{"icon":"👘","title":"Sức mạnh thị giác","desc":"Trang phục và màu sắc khiến Katê trở thành một trong những lễ hội giàu ấn tượng hình ảnh nhất."}],"galleryHero":"/images/cham.jpg","galleryGrid":["/images/cham.jpg","/images/banner1.jpg","/images/banner2.jpg","/images/banner3.jpg","/images/cham.jpg","/images/banner1.jpg"],"inShortText":"Katê là lễ hội tiêu biểu của người Chăm, nơi đền tháp, âm nhạc, trang phục và tinh thần cộng đồng cùng tái hiện một di sản văn hóa đặc sắc của miền Trung Việt Nam.","discoverMore":[{"image":"/images/cham.jpg","title":"Tháp Chăm và không gian nghi lễ","desc":"Khám phá vai trò của kiến trúc tháp trong đời sống tín ngưỡng cộng đồng Chăm."},{"image":"/images/banner1.jpg","title":"Âm nhạc và điệu múa Katê","desc":"Tìm hiểu những yếu tố trình diễn làm nên sức sống của ngày hội."},{"image":"/images/banner2.jpg","title":"Văn hóa Chăm trong hiện tại","desc":"Cảm nhận cách cộng đồng gìn giữ di sản qua một lễ hội vẫn đang sống động hôm nay."}],"labels":{"whatIsItTitle":"Lễ hội Katê là gì?","dateLabel":"Thời gian","locationLabel":"Địa điểm","participantsLabel":"Thành phần tham gia","celebrationTitle":"Lễ hội Katê diễn ra như thế nào?","feelsLikeTitle":"Trải nghiệm không khí Katê","keyTraditionsTitle":"Những nét truyền thống nổi bật","traditionalFoodsTitle":"Ẩm thực trong mùa Katê","traditionalFoodsSubtitle":"Ẩm thực và lễ vật góp phần làm rõ tinh thần cộng đồng và tính thiêng của ngày hội.","northRegionLabel":"Miền Bắc","centralRegionLabel":"Miền Trung","southRegionLabel":"Miền Nam","culturalMeaningsTitle":"Ý nghĩa văn hóa","interestingFactsTitle":"Điều thú vị về lễ hội Katê","galleryTitle":"Lễ hội Katê qua hình ảnh","inShortTitle":"Tóm lược","discoverMoreTitle":"Khám phá thêm về lễ hội Katê"}}',HoatDong=1,NgayCapNhat=SYSUTCDATETIME()
WHERE MaLeHoi='kate';
GO

UPDATE dbo.LeHoi SET
  LoaiBanGhi='FESTIVAL',ThuTuHienThi=7,TieuDeVI=N'Lễ hội Nghinh Ông',TieuDePhuVI=N'Lễ hội tín ngưỡng vùng biển',ShortTitleVI=N'Nghinh Ông',MoTaNganVI=N'Lễ hội của cư dân vùng biển nhằm cầu mong bình an, mưa thuận gió hòa và mùa đánh bắt thuận lợi.',HeroDescVI=N'Lễ hội phản ánh đời sống tín ngưỡng của ngư dân và mối gắn bó giữa con người với biển cả.',ViTriVI=N'Các tỉnh ven biển Nam Bộ',NgayLeVI=N'Thường tổ chức theo mùa lễ của địa phương',TagVI=N'Tín ngưỡng',TagColor='#6366f1',ImageUrl=N'/images/banner3.jpg',ImageAltVI=N'Lễ hội Nghinh Ông',TimelineMonthVI=N'Tháng 12',TimelineSeasonVI=N'Mùa đông',TimelineImageUrl=N'/images/banner3.jpg',TimelineImageAltVI=N'Lễ hội Nghinh Ông',TimelineColor='#6366f1',
  NoiDungJsonVI=N'{"whatIsItContext":["Lễ hội Nghinh Ông là lễ hội tín ngưỡng quan trọng của cư dân vùng biển, thể hiện niềm tin vào sự che chở của thần biển và ước vọng về những chuyến ra khơi bình an.","Đây cũng là dịp cộng đồng ngư dân tưởng niệm, cầu ngư và cùng nhau củng cố mối gắn bó giữa đời sống tâm linh với biển cả."],"quickFacts":{"date":"Thường tổ chức theo mùa lễ của địa phương","location":"Các tỉnh ven biển Nam Bộ","participants":"Ngư dân, cư dân địa phương và du khách"},"howItIsCelebrated":[{"phase":"Chuẩn bị","title":"Trang hoàng đình, lăng và thuyền lễ","desc":["Cộng đồng chuẩn bị không gian thờ tự, cờ phướn và các nghi thức cần thiết cho ngày lễ.","Không khí chuẩn bị cho thấy sự thành kính và kỳ vọng của ngư dân trước mùa biển mới."],"image":"/images/banner3.jpg","align":"left"},{"phase":"Chính lễ","title":"Nghi thức rước và cầu ngư","desc":["Các nghi thức rước Ông, dâng lễ và cầu mong sóng yên biển lặng là trung tâm của lễ hội.","Tinh thần hướng về biển thể hiện rõ trong từng biểu tượng, lời khấn và hoạt động cộng đồng."],"image":"/images/banner1.jpg","align":"right"},{"phase":"Phần hội","title":"Giao lưu cộng đồng vùng biển","desc":["Sau nghi lễ là các hoạt động văn nghệ, gặp gỡ và sinh hoạt cộng đồng của ngư dân.","Lễ hội vì thế vừa mang tính tâm linh vừa là dịp củng cố tinh thần đoàn kết của xóm biển."],"image":"/images/banner2.jpg","align":"left"}],"whatTetFeelsLike":{"leftText":["Không gian: Cờ phướn, thuyền lễ và không khí biển tạo nên một sắc thái rất riêng của lễ hội vùng duyên hải.","Âm thanh: Tiếng sóng, tiếng trống, tiếng người gọi nhau và âm nhạc lễ hòa vào nhau thành một bầu không khí đặc biệt.","Nhịp điệu: Vừa trang nghiêm trong nghi lễ vừa sôi nổi trong phần hội cộng đồng."],"rightText":["Con người: Những người gắn bó cả đời với biển tham gia lễ hội bằng tất cả niềm tin và sự thành kính.","Cảm xúc: Đó là sự biết ơn, hy vọng và niềm mong đợi về một mùa biển thuận lợi.","Trải nghiệm: Nghinh Ông giúp người tham dự cảm nhận rõ đời sống tâm linh của cư dân vùng biển Nam Bộ."],"image":"/images/banner3.jpg"},"keyTraditionsDocs":[{"image":"/images/banner3.jpg","title":"Rước Ông","desc":"Nghi thức tiêu biểu làm nên bản sắc của lễ hội Nghinh Ông."},{"image":"/images/banner1.jpg","title":"Cầu ngư","desc":"Lời cầu mong bình an và mưa thuận gió hòa cho đời sống ngư dân."},{"image":"/images/banner2.jpg","title":"Sinh hoạt xóm biển","desc":"Phần hội thể hiện tinh thần đoàn kết và tính cộng đồng của cư dân vùng biển."}],"traditionalFoods":[{"image":"/images/banner1.jpg","title":"Món ăn vùng biển","desc":"Ẩm thực phản ánh nhịp sống và nguồn sản vật của cư dân ven biển."},{"image":"/images/banner2.jpg","title":"Cỗ lễ cộng đồng","desc":"Những món ăn chuẩn bị cho dịp lễ vừa mang tính nghi thức vừa mang tính sẻ chia."},{"image":"/images/banner3.jpg","title":"Hương vị xóm chài","desc":"Ẩm thực giúp khắc họa đời sống thường nhật của cộng đồng gắn với biển."}],"regionalFoods":{"north":[{"image":"/images/banner1.jpg","title":"Góc nhìn từ miền khác","desc":"Lễ hội vùng biển Nam Bộ tạo nên trải nghiệm khác biệt với du khách phương xa."}],"central":[{"image":"/images/banner2.jpg","title":"Kết nối văn hóa biển","desc":"Nhiều cộng đồng ven biển Việt Nam có những nét tương đồng trong tín ngưỡng cầu ngư."}],"south":[{"image":"/images/banner3.jpg","title":"Ẩm thực xóm chài Nam Bộ","desc":"Hương vị biển cả là phần không thể thiếu trong sinh hoạt cộng đồng ngày lễ."}]},"culturalMeaningsDocs":[{"icon":"🌊","title":"Niềm tin vào biển cả","desc":"Nghinh Ông phản ánh mối quan hệ tâm linh giữa con người với đại dương.","colorClass":"highlight-red"},{"icon":"🙏","title":"Cầu bình an cho ngư dân","desc":"Đây là lớp ý nghĩa quan trọng nhất trong đời sống vùng biển.","colorClass":"highlight-orange"},{"icon":"🤝","title":"Củng cố đoàn kết xóm biển","desc":"Lễ hội là dịp để cộng đồng ven biển cùng nhau chia sẻ niềm tin và sinh hoạt chung.","colorClass":"highlight-yellow"}],"interestingFactsDocs":[{"icon":"⛵","title":"Dấu ấn của nghề biển","desc":"Nghinh Ông gắn chặt với đời sống lao động và tâm thức của cư dân đi biển."},{"icon":"🐋","title":"Biểu tượng linh thiêng","desc":"Hình tượng Ông trong tín ngưỡng dân gian thể hiện niềm tin vào sự che chở giữa sóng gió."},{"icon":"🎏","title":"Sắc màu lễ hội ven biển","desc":"Cờ phướn, thuyền lễ và không khí bến nước tạo nên nét thị giác rất riêng của Nghinh Ông."}],"galleryHero":"/images/banner3.jpg","galleryGrid":["/images/banner3.jpg","/images/banner1.jpg","/images/banner2.jpg","/images/festival_banner.jpg","/images/banner3.jpg","/images/banner1.jpg"],"inShortText":"Nghinh Ông là lễ hội của niềm tin biển cả, của lời cầu bình an và của tinh thần cộng đồng bền chặt nơi những xóm chài Nam Bộ.","discoverMore":[{"image":"/images/banner3.jpg","title":"Tín ngưỡng vùng biển Nam Bộ","desc":"Tìm hiểu cách cư dân ven biển gửi gắm niềm tin và hy vọng qua lễ hội."},{"image":"/images/banner1.jpg","title":"Nghi thức cầu ngư","desc":"Khám phá những biểu tượng gắn với ước vọng bình an và mùa biển thuận lợi."},{"image":"/images/banner2.jpg","title":"Đời sống xóm chài trong mùa lễ","desc":"Cảm nhận nhịp sinh hoạt cộng đồng của cư dân biển qua phần hội và những cuộc gặp gỡ."}],"labels":{"whatIsItTitle":"Lễ hội Nghinh Ông là gì?","dateLabel":"Thời gian","locationLabel":"Địa điểm","participantsLabel":"Thành phần tham gia","celebrationTitle":"Lễ hội Nghinh Ông diễn ra như thế nào?","feelsLikeTitle":"Trải nghiệm không khí Nghinh Ông","keyTraditionsTitle":"Những nét truyền thống nổi bật","traditionalFoodsTitle":"Ẩm thực trong mùa lễ Nghinh Ông","traditionalFoodsSubtitle":"Ẩm thực vùng biển góp phần phản ánh đời sống cộng đồng và không gian lễ hội ven duyên hải.","northRegionLabel":"Miền Bắc","centralRegionLabel":"Miền Trung","southRegionLabel":"Miền Nam","culturalMeaningsTitle":"Ý nghĩa văn hóa","interestingFactsTitle":"Điều thú vị về lễ hội Nghinh Ông","galleryTitle":"Lễ hội Nghinh Ông qua hình ảnh","inShortTitle":"Tóm lược","discoverMoreTitle":"Khám phá thêm về lễ hội Nghinh Ông"}}',HoatDong=1,NgayCapNhat=SYSUTCDATETIME()
